-- areas batch 3/20 (10 rows)
BEGIN;

INSERT INTO areas (id, data, updated_at)
SELECT (value->>'id')::text, value, now()
FROM jsonb_array_elements('[{"id":"bordon-gu35","name":"Bordon","village":"Bordon","town":"Farnham","county":"Hampshire","postcode":"GU35","hubCity":"Guildford","regionDir":"","settlementType":"","subRegion":"Farnham","coords":{"lat":51.10716,"lng":-0.87768},"coordsSource":"postcode-outward-approx","houseTypeIds":[],"status":"researched","priceSummary":null,"councilTaxBand":null,"overview":"A town of around 16,000 residents in the East Hampshire district, set in the royal Woolmer Forest some five miles south-east of Alton. Bordon is unlike its nearest peers (Petersfield, Farnham, Alton) in that it never grew as a market town: the camp was laid out by the Royal Engineers in 1899 and from 1903 the town developed around the Army, latterly as a base for the Royal Electrical and Mechanical Engineers. The MoD withdrew in 2015 and a 15-year, circa £1bn regeneration partnership (Defence Infrastructure Organisation, Dorchester Regeneration, Taylor Wimpey, East Hants and Hampshire County Councils) is rebuilding the former Prince Philip Barracks site as a ''Green Town'' delivering up to 3,350 new homes, a new town centre, schools, a health hub and the 54-hectare Hogmoor Inclosure SANGS. The Sainsbury''s that anchors the emerging town centre broke ground in 2025 with first customers due summer 2026. Bordon shares a civil parish (Whitehill) with the contiguous village of Lindford.","character":"A working town in the middle of a long, public-led rebuild. Older Edwardian and post-war military housing on the A325 spine sits alongside new-build Quebec Park and Prince Philip Park phases (Taylor Wimpey, Bovis and others). Heathland, woodland and the Woolmer Forest SSSI are immediately to the south; the new walking and cycling ''Green Loop'' threads the town. Mixed demographic — ex-service families, commuters using Liphook for the Portsmouth Direct line, and first-time buyers priced out of Farnham or Haslemere.","amenities":["Phoenix Theatre and Arts Centre","Mill Chase Leisure Centre","Hogmoor Inclosure (54 ha SANGS, café, skate park)","Bordon and Oakhanger Sports Pavilion","The Shed (dining and events venue, town centre)","Tesco Superstore (Chalet Hill)","Sainsbury''s (16,000 sq ft, opening summer 2026)","Bordon Health Centre","St Mark''s Church, Whitehill","Bordon Library"],"schools":[{"name":"Bordon Infant School","phase":"Primary","ofsted":null,"distance":"town centre","url":"https://reports.ofsted.gov.uk/provider/21/150418"},{"name":"Bordon Junior School","phase":"Primary","ofsted":null,"distance":"town centre","url":"https://reports.ofsted.gov.uk/provider/21/146002"},{"name":"Weyford Nursery and Primary Academy","phase":"Primary","ofsted":null,"distance":"0.4 mi","url":"https://reports.ofsted.gov.uk/provider/21/148215"},{"name":"Oakmoor School","phase":"Secondary","ofsted":"Good (2021); 2026 inspection under new report-card framework, no single overall grade","distance":"town centre","url":"https://reports.ofsted.gov.uk/provider/23/140182"}],"transport":{"commutes":[{"to":"London Waterloo","time":"1h 1m – 1h 21m","mode":"drive to Liphook + direct South Western Railway","source":"https://www.thetrainline.com/train-times/liphook-to-london-waterloo"},{"to":"Portsmouth & Southsea","time":"~45m","mode":"drive to Liphook + direct South Western Railway","source":"https://www.thetrainline.com/stations/liphook"}],"nearestStation":"Liphook (3.7 mi)","roads":"A325 runs through the town; A3 (London–Portsmouth) ~2 mi east at Liphook/Hindhead; Hindhead Tunnel since 2011 has cut A3 journey times north"},"prices":{"avgSold12Mo":420411,"avgDetached":null,"avgSemi":null,"avgTerraced":null,"avgFlat":null,"source":"https://www.rightmove.co.uk/house-prices/gu35.html","asOf":"2026-05"},"thingsToDo":["Hogmoor Inclosure walking, cycling, skate park","Deadwater Valley Local Nature Reserve","Shipwrights Way long-distance trail","Woolmer Forest SSSI heathland walks","Phoenix Theatre programme","Alice Holt Forest (Go Ape, ~6 mi north)"],"placesToEat":[{"name":"The Shed","type":"Bar and dining","notes":"Town-centre venue, recently refurbished as part of the regeneration","url":"https://www.princephilippark.co.uk/"},{"name":"The Royal Exchange","type":"Pub","notes":"Long-standing town pub on Lindford Road","url":"https://www.useyourlocal.com/"}],"pros":["Among the cheapest stock in the GU postcode commuter belt (GU35 avg £420k vs neighbouring GU30 Liphook well above £500k)","Substantial new build supply with developer warranties via Quebec Park / Prince Philip Park","Hogmoor Inclosure and Woolmer Forest deliver real countryside on the doorstep","Liphook station (3.7 mi) gives direct ~1-hour London Waterloo trains","Town centre, Sainsbury''s, health hub and second primary still being delivered — capital values likely to follow infrastructure"],"cons":["No railway station of its own (line lifted in 1957); car or bus needed for the train","Town centre still half-built — the new Sainsbury''s only opens summer 2026, new primary not due until 2028","Secondary catchment Oakmoor (rated Good in 2021) is the only mainstream secondary in town; sixth-form provision is limited locally","Heavy through-traffic on the A325 spine","Older estate stock (ex-MoD married quarters) varies sharply in condition"],"whoItSuits":"First-time buyers and young families priced out of Farnham, Liphook or Haslemere but who want the same Portsmouth Direct line and South Downs/National Park access. Buyers who are comfortable being in a town mid-regeneration rather than a finished one — there is upside if you take the long view, but the town centre, second primary and health hub are still being built out into 2028+. Ex-service households retain a strong presence. Less suited to buyers wanting an immediate, mature market-town feel: for that, Alton or Petersfield are better.","broadbandMedianMbps":null,"nearestStation":"Liphook (3.7 mi)","primarySupermarket":"Tesco Superstore, Chalet Hill, Bordon (in town); Sainsbury''s opening summer 2026","images":[],"sources":[{"label":"Wikipedia — Bordon","url":"https://en.wikipedia.org/wiki/Bordon"},{"label":"Visit Hampshire — Bordon and Whitehill","url":"https://www.visit-hampshire.co.uk/explore/bordon-and-whitehill-p477591"},{"label":"Whitehill & Bordon Regeneration","url":"http://whitehillbordon.com/about/"},{"label":"East Hants DC — Sainsbury''s groundbreaking 2025","url":"https://www.easthants.gov.uk/news/2025/spades-ground-new-whitehill-bordon-sainsburys-store"},{"label":"Whitehill Town Council — regeneration update Jan 2026","url":"https://www.whitehilltowncouncil.gov.uk/regeneration-of-the-town"},{"label":"Ofsted — Oakmoor School","url":"https://reports.ofsted.gov.uk/provider/23/140182"},{"label":"East Hants DC — Council Tax bands 2026/27","url":"https://www.easthants.gov.uk/sites/default/files/2026-03/Council%20tax%20per%20valuation%20band%202026-27.pdf"},{"label":"Rightmove — GU35 house prices","url":"https://www.rightmove.co.uk/house-prices/gu35.html"}]},{"id":"bossington-so20","name":"Bossington","village":"Bossington","town":"Stockbridge","county":"Hampshire","postcode":"SO20","hubCity":"Southampton","regionDir":"North","settlementType":"Non-City","subRegion":"Stockbridge","coords":{"lat":51.10256,"lng":-1.4854},"coordsSource":"postcode-outward-approx","houseTypeIds":[],"status":"researched","priceSummary":null,"councilTaxBand":null,"overview":"Bossington is a very small village and civil parish in Test Valley, near Houghton and Stockbridge, set beside River Test country. Historic references note a medieval settlement history and listed buildings including St James church and Bossington House. Today it is a tiny, low-density rural settlement with strong estate and landscape character rather than a service village.","character":"Exclusive, low-density hamlet/parish feel with estate land, fishing heritage and minimal through-traffic outside local lanes.","amenities":["No major retail in-village; daily services usually in Stockbridge/Romsey","Rural church and listed-building heritage setting","Access to walking and fly-fishing country in the River Test valley"],"schools":[{"name":"Stockbridge Primary School","phase":"Primary","type":"State","ofsted":"Good (2023)","distance":"~2–4 miles","url":"https://reports.ofsted.gov.uk/provider/21/116028"},{"name":"Test Valley School","phase":"Secondary","type":"State","ofsted":"Good (2023)","distance":"~2–4 miles","url":"https://reports.ofsted.gov.uk/provider/23/116430"}],"transport":{"commutes":[{"to":"Stockbridge","mode":"Drive","typical":"~5 min","notes":"nearby via local roads"},{"to":"Southampton","mode":"Drive","typical":"~30–40 min","notes":"route depends on river/lane approach"},{"to":"London Waterloo","mode":"Train (from Andover)","typical":"~1h15–1h30 rail + ~15–20 min drive","notes":"no station in parish"}]},"prices":{"summary":"SO20 transactions are typically led by detached and period village housing across the Test Valley.","average":"£557,054","detached":"£808,571","semiDetached":"£426,364","terraced":"£345,769","flat":"£152,000","asOf":"2026-04","sourceUrl":"https://www.rightmove.co.uk/house-prices/SO20.html"},"thingsToDo":["Countryside walking around Test Valley lanes","Fly-fishing visits in nearby estate waters (where permitted)","Visits to Stockbridge, Houghton and Mottisfont area"],"placesToEat":["The Greyhound on the Test, Stockbridge","The Three Cups Inn, Stockbridge","Pubs and cafés in Romsey/Stockbridge catchment"],"pros":["Highly peaceful setting","Strong rural and heritage character","Close to attractive Test Valley destinations"],"cons":["Extremely limited in-village services","Car dependency for schools/shopping/rail","Very limited transaction volume and housing turnover"],"whoItSuits":"Suited to buyers seeking a very quiet hamlet lifestyle with easy car access to Stockbridge, and who are comfortable with minimal walkable services.","broadbandMedianMbps":null,"nearestStation":null,"primarySupermarket":null,"images":[],"sources":[{"label":"Wikipedia — Bossington, Hampshire","url":"https://en.wikipedia.org/wiki/Bossington%2C_Hampshire"},{"label":"Streetfinder SO20 coverage (includes Ashley/Bossington/Brook/Chilbolton Down)","url":"https://www.streetfinder.co.uk/postcode/SO20.htm"},{"label":"Rightmove House Prices SO20","url":"https://www.rightmove.co.uk/house-prices/SO20.html"},{"label":"Ofsted — Stockbridge Primary School","url":"https://reports.ofsted.gov.uk/provider/21/116028"},{"label":"Ofsted — Test Valley School","url":"https://reports.ofsted.gov.uk/provider/23/116430"},{"label":"Bossington Estate (local context)","url":"https://www.bossingtonestate.com/"}]},{"id":"bowerchalke-sp5","name":"Bowerchalke","village":"Bowerchalke","town":"Salisbury","county":"Wiltshire","postcode":"SP5","hubCity":"Salisbury","regionDir":"","settlementType":"","subRegion":"Salisbury","coords":{"lat":51.01404,"lng":-1.85236},"coordsSource":"postcode-outward-approx","houseTypeIds":[],"status":"researched","priceSummary":null,"councilTaxBand":null,"overview":"Bowerchalke is in the Salisbury area of Wiltshire (SP5), and sits in the rural-to-commuter belt around Salisbury. Historic references and parish records show long-established settlement patterns, with modern housing mostly as infill around older cores. Day-to-day life depends on local village facilities plus Salisbury for larger services. The area appeals to buyers who want a quieter setting but still need practical links to the city.","character":"Bowerchalke has a village-scale layout with mixed period and modern homes, a parish-centred feel, and surrounding countryside as a dominant part of daily character.","amenities":["Parish/community facilities in Bowerchalke","Nearby shopping and services in Salisbury","Local walking routes and countryside access"],"schools":[{"name":"Primary schools serving Bowerchalke","phase":"Primary","distance":"typically local catchment / short drive","url":"https://get-information-schools.service.gov.uk/"},{"name":"Secondary schools in Salisbury","phase":"Secondary","distance":"usually reached by bus or car","url":"https://get-information-schools.service.gov.uk/"}],"transport":{"nearestStation":"Salisbury","roads":"Village roads generally connect to the A36/A30 corridor for Salisbury access.","commutes":[{"to":"Salisbury","time":"often around 10-30 minutes by car depending on exact start point and traffic","mode":"Car","source":"https://www.google.com/maps"},{"to":"London Waterloo","time":"typically around 1h30-1h40 from Salisbury station services","mode":"Rail (from Salisbury)","source":"https://www.nationalrail.co.uk/stations/salisbury/"}]},"prices":{"avgSold12Mo":null,"source":"https://www.rightmove.co.uk/house-prices/SP5.html","asOf":"2026-05-24"},"thingsToDo":["Village and valley walks","Visits to Salisbury Cathedral/cultural venues","Trips to local heritage sites and surrounding countryside"],"placesToEat":["Country pubs in surrounding villages","Wider restaurant and café options in Salisbury"],"pros":["Quieter environment than central Salisbury","Reasonable access to city services and rail via Salisbury station"],"cons":["Many errands still require driving","Public transport coverage varies by village and time of day"],"whoItSuits":"Best for buyers prioritising village character and countryside access, while accepting regular trips into Salisbury for wider amenities and commuting connections.","broadbandMedianMbps":null,"nearestStation":null,"primarySupermarket":null,"images":[],"sources":["https://en.wikipedia.org/wiki/Bowerchalke","https://www.wiltshire.gov.uk/","https://get-information-schools.service.gov.uk/","https://www.rightmove.co.uk/house-prices/SP5.html","https://www.nationalrail.co.uk/stations/salisbury/","https://www.google.com/maps"]},{"id":"bradley-gu34","name":"Bradley","village":"Bradley","town":"Alton","county":"Hampshire","postcode":"GU34","hubCity":"Guildford","regionDir":"","settlementType":"","subRegion":"Alton","coords":{"lat":51.13024,"lng":-0.97844},"coordsSource":"postcode-outward-approx","houseTypeIds":[],"status":"researched","priceSummary":null,"councilTaxBand":null,"overview":"Bradley is a small civil parish and hamlet of around 200 residents in the Basingstoke and Deane district, on the chalk uplands between Alton and Basingstoke. The Royal Mail post town is Alresford and the postal district is GU35 rather than GU34, although the seed data places it under Alton; Basingstoke is about six and a half miles north, Alton five and a half miles south-east. The village was first recorded in a charter of Edward the Elder dated 909, was held with Overton at Domesday, and later passed through several manorial families. The parish covers 975 acres at a high point of 170 m and contains no separate hamlets. Bradley is small enough to have no shop, school or pub, and most daily needs are met by car, either north to Basingstoke or south to Alton or Alresford. The Grade II*-listed Church of All Saints anchors the village.","character":"Tightly compact estate-influenced hamlet with seven Grade II buildings (large farmhouses and a K6 telephone box) plus the Grade II* All Saints church, set among arable fields and small copses. No through-road of any size; access via narrow chalk lanes. Building stock is mostly listed farmhouses with a small handful of post-war additions; planning regime is tight.","amenities":["All Saints Church (Grade II*)","K6 telephone box (Grade II listed)","Active parish meeting","Nearest shop and post office: Preston Candover or Old Alresford (~3 mi)"],"schools":[{"name":"Preston Candover Church of England Primary School","phase":"Primary","ofsted":null,"distance":"3.0 mi","url":"https://reports.ofsted.gov.uk/"}],"transport":{"commutes":[{"to":"London Waterloo (via Alton)","time":"1h 13m + drive","mode":"drive + train","source":"https://www.thetrainline.com/stations/alton"},{"to":"London Waterloo (via Basingstoke)","time":"~50m + drive","mode":"drive + train (faster Basingstoke route)","source":"https://www.nationalrail.co.uk/"}],"nearestStation":"Alton (~6 mi) or Basingstoke (~7 mi)","roads":"B3046 ~1 mi; A339 ~3 mi; A31 ~5 mi; M3 J7 (Basingstoke) ~9 mi"},"prices":{"avgSold12Mo":null,"avgDetached":null,"avgSemi":null,"avgTerraced":null,"avgFlat":null,"source":"https://www.rightmove.co.uk/house-prices/gu34.html","asOf":"2026-05"},"thingsToDo":["Walking the Candover chalk lanes","Visiting All Saints Church (Grade II*)","Preston Candover village shop and pub (3 mi)","Hattingley Valley Wines (~4 mi)","Lasham Gliding Club (~5 mi)"],"placesToEat":[{"name":"Purefoy Arms, Preston Candover","type":"Country pub","notes":"Nearest pub of note; mains around £18–£28","url":"https://thepurefoyarms.co.uk/"}],"pros":["Quiet chalk-country position equidistant from Basingstoke and Alton","Grade II* church and high concentration of listed buildings","Tight planning regime preserves rural character","Faster trains available from Basingstoke (under an hour to Waterloo)"],"cons":["No shop, school, pub or station within the parish","Royal Mail post town is Alresford though seed data lists Alton","Limited listed-property stock; turnover is rare","Mobile signal patchy on lower chalk lanes"],"whoItSuits":"Buyers willing to commit fully to a car-dependent life among a few dozen households, and to source most of their amenities from Preston Candover, Old Alresford or Basingstoke. Strong fit for retirees and remote workers wanting an unusually unspoilt chalk-down setting; weaker fit for first-time buyers, who will struggle on price and choice given the size of the listed-property stock. Note that the postal district appears as GU35 on the Wikipedia infobox and the seed data tags this record as GU34 — buyers should verify the precise postcode against the property.","broadbandMedianMbps":null,"nearestStation":"Alton (~6 mi)","primarySupermarket":"Waitrose, Alresford (~5 mi) or Sainsbury''s, Alton (~6 mi)","images":[],"sources":["https://en.wikipedia.org/wiki/Bradley,_Hampshire","https://search.savills.com/list/houses-for-sale/england/hampshire/bradley/so24","https://www.hamptons.co.uk/estate-agents/bradley","https://www.rightmove.co.uk/house-prices/gu34.html","https://www.thetrainline.com/stations/alton","https://www.streetlist.co.uk/gu/gu34"]},{"id":"braishfield-so51","name":"Braishfield","village":"Braishfield","town":"Winchester","county":"Hampshire","postcode":"SO51","hubCity":"Southampton","regionDir":"North","settlementType":"Non-City","subRegion":"Winchester","coords":{"lat":50.99684,"lng":-1.50936},"coordsSource":"postcode-outward-approx","houseTypeIds":[],"status":"researched","priceSummary":null,"councilTaxBand":null,"overview":"Braishfield is a Hampshire village north-east of Romsey, known for its spring flowers and elevated views over Test Valley countryside. It has long agricultural roots and retains a classic village form centred on parish life and local lanes. Today it offers a desirable rural setting within practical reach of Romsey, Winchester and Southampton routes.","character":"Traditional village with period homes, parish institutions and strong community identity.","amenities":["Village church, hall and recreation facilities","Primary schooling and local pub/social spaces in village context","Broader supermarkets/rail connections in Romsey"],"schools":[{"name":"Braishfield Primary School","phase":"Primary","type":"State","ofsted":null,"distance":"In village","url":"https://www.braishfield.hants.sch.uk/"},{"name":"The Romsey School","phase":"Secondary","type":"State","ofsted":null,"distance":"~4-6 miles","url":"https://www.theromseyschool.org/"}],"transport":{"commutes":[{"to":"Romsey","mode":"Drive","typical":"~10-15 min","notes":"Nearest major services and station"},{"to":"Southampton","mode":"Drive","typical":"~25-35 min","notes":"Via M27 corridor from Romsey side"}]},"prices":{"summary":"SO51 prices in and around Braishfield are typically buoyed by village demand and commuter appeal to the Southampton/Winchester corridor.","asOf":"2026-05","sourceUrl":"https://www.rightmove.co.uk/house-prices/SO51.html"},"thingsToDo":["Seasonal walks and countryside trails around village lanes","Romsey Abbey, market town amenities and Test Valley attractions nearby"],"placesToEat":["Village/nearby country pubs and Romsey restaurants"],"pros":["Attractive village setting with strong community feel","Convenient road links to Romsey and Southampton"],"cons":["Limited in-village retail breadth","Public transport less flexible than town locations"],"whoItSuits":"Well suited to families and professionals seeking a picturesque Hampshire village with a real community core and manageable driving access to major employment centres.","broadbandMedianMbps":null,"nearestStation":null,"primarySupermarket":null,"images":[],"sources":[{"label":"Wikipedia — Braishfield","url":"https://en.wikipedia.org/wiki/Braishfield"},{"label":"Braishfield Primary School","url":"https://www.braishfield.hants.sch.uk/"},{"label":"Rightmove House Prices SO51","url":"https://www.rightmove.co.uk/house-prices/SO51.html"},{"label":"Romsey School","url":"https://www.theromseyschool.org/"}]},{"id":"bramdean-so24","name":"Bramdean","village":"Bramdean","town":"Petersfield","county":"Hampshire","postcode":"SO24","hubCity":"Southampton","regionDir":"North","settlementType":"Non-City","subRegion":"Petersfield","coords":{"lat":51.08048,"lng":-1.15888},"coordsSource":"postcode-outward-approx","houseTypeIds":[],"status":"researched","priceSummary":null,"councilTaxBand":null,"overview":"Bramdean is a village in the South Downs-adjacent countryside east of Winchester and north of Petersfield. It has a historic rural parish setting with church and village institutions tied to surrounding farmland. Modern life in Bramdean is quiet and low-density, with residents typically relying on Alresford and Winchester for higher-order services.","character":"Small historic village with downland scenery and a calm rural rhythm.","amenities":["Village hall/church-led community life","Local footpaths and countryside recreation","Most shopping and healthcare needs met in Alresford/Winchester"],"schools":[{"name":"Cheriton Primary School","phase":"Primary","type":"State","ofsted":null,"distance":"~3-5 miles","url":"https://www.cheriton.hants.sch.uk/"},{"name":"Perins School, Alresford","phase":"Secondary","type":"State","ofsted":null,"distance":"~6-9 miles","url":"https://www.perins.net/"}],"transport":{"commutes":[{"to":"Winchester","mode":"Drive","typical":"~25-35 min","notes":"Via A31 approach roads"},{"to":"Petersfield","mode":"Drive","typical":"~20-30 min","notes":"Via rural B-road routes"}]},"prices":{"summary":"SO24 prices near Bramdean tend to reflect scarcity of stock and demand for rural homes close to South Downs amenities.","asOf":"2026-05","sourceUrl":"https://www.rightmove.co.uk/house-prices/SO24.html"},"thingsToDo":["Walk and cycle South Downs-edge routes","Visit nearby Hinton Ampner and Alresford attractions"],"placesToEat":["Country pubs in Cheriton/Alresford/Petersfield hinterland"],"pros":["Peaceful countryside setting with strong landscape value","Accessible to multiple market towns by car"],"cons":["Limited day-to-day amenities within the village","Car use is essential for most households"],"whoItSuits":"A good fit for buyers who value rural tranquillity and scenery, and who are comfortable travelling to nearby towns for schools, shopping and rail connections.","broadbandMedianMbps":null,"nearestStation":null,"primarySupermarket":null,"images":[],"sources":[{"label":"Wikipedia — Bramdean","url":"https://en.wikipedia.org/wiki/Bramdean"},{"label":"Rightmove House Prices SO24","url":"https://www.rightmove.co.uk/house-prices/SO24.html"},{"label":"Perins School","url":"https://www.perins.net/"},{"label":"Winchester City Council","url":"https://www.winchester.gov.uk/"}]},{"id":"bramshaw-so43","name":"Bramshaw","village":"Bramshaw","town":"Salisbury","county":"Hampshire","postcode":"SO43","hubCity":"Southampton","regionDir":"North","settlementType":"Non-City","subRegion":"Salisbury","coords":{"lat":50.86808,"lng":-1.57228},"coordsSource":"postcode-outward-approx","houseTypeIds":[],"status":"researched","priceSummary":null,"councilTaxBand":null,"overview":"Bramshaw sits on the Hampshire/Wiltshire edge of the New Forest, with a dispersed settlement pattern, common land and long-standing rural heritage. The area is known for forest ponies, open heath and links to nearby Lyndhurst and Salisbury routes. It offers a distinctive New Forest lifestyle with protected landscapes and tourism-driven local activity.","character":"Dispersed New Forest village character with commons, lanes and mixed historic housing.","amenities":["Parish church and village institutions with active local groups","Forest access, riding/cycling/walking routes and visitor economy facilities nearby","Wider shops and services in Lyndhurst, Romsey and Salisbury corridors"],"schools":[{"name":"Bramshaw C of E Primary School","phase":"Primary","type":"State","ofsted":null,"distance":"In village area","url":"https://www.bramshaw.hants.sch.uk/"},{"name":"The Burgate School, Fordingbridge","phase":"Secondary","type":"State","ofsted":null,"distance":"~6-9 miles","url":"https://www.theburgate.com/"}],"transport":{"commutes":[{"to":"Southampton","mode":"Drive","typical":"~30-45 min","notes":"Via Lyndhurst/M27 route"},{"to":"Salisbury","mode":"Drive","typical":"~25-35 min","notes":"Via A36 corridor"}]},"prices":{"summary":"SO43/New Forest pricing is typically supported by high landscape demand and constrained housing supply in protected areas.","asOf":"2026-05","sourceUrl":"https://www.rightmove.co.uk/house-prices/SO43.html"},"thingsToDo":["New Forest walks, cycling and wildlife watching","Explore nearby Lyndhurst museums and forest villages"],"placesToEat":["Country pubs and hotel restaurants in Bramshaw/Lyndhurst/Fordingbridge area"],"pros":["Outstanding natural setting and recreation access","Strong place identity tied to the New Forest"],"cons":["Planning constraints can limit change/expansion","Peak-season visitor traffic can affect travel times"],"whoItSuits":"Ideal for nature-focused households and remote/hybrid workers who prioritise protected-landscape living and accept rural transport trade-offs.","broadbandMedianMbps":null,"nearestStation":null,"primarySupermarket":null,"images":[],"sources":[{"label":"Wikipedia — Bramshaw","url":"https://en.wikipedia.org/wiki/Bramshaw"},{"label":"New Forest National Park","url":"https://www.newforestnpa.gov.uk/"},{"label":"Rightmove House Prices SO43","url":"https://www.rightmove.co.uk/house-prices/SO43.html"},{"label":"The Burgate School","url":"https://www.theburgate.com/"}]},{"id":"breamore-sp6","name":"Breamore","village":"Breamore","town":"Salisbury","county":"Wiltshire","postcode":"SP6","hubCity":"Salisbury","regionDir":"","settlementType":"","subRegion":"Salisbury","coords":{"lat":50.92608,"lng":-1.79904},"coordsSource":"postcode-outward-approx","houseTypeIds":[],"status":"researched","priceSummary":null,"councilTaxBand":null,"overview":"Breamore is in the Salisbury area of Wiltshire (SP6), and sits in the rural-to-commuter belt around Salisbury. Historic references and parish records show long-established settlement patterns, with modern housing mostly as infill around older cores. Day-to-day life depends on local village facilities plus Salisbury for larger services. The area appeals to buyers who want a quieter setting but still need practical links to the city.","character":"Breamore has a village-scale layout with mixed period and modern homes, a parish-centred feel, and surrounding countryside as a dominant part of daily character.","amenities":["Parish/community facilities in Breamore","Nearby shopping and services in Salisbury","Local walking routes and countryside access"],"schools":[{"name":"Primary schools serving Breamore","phase":"Primary","distance":"typically local catchment / short drive","url":"https://get-information-schools.service.gov.uk/"},{"name":"Secondary schools 