phase":"All-through","type":"Independent","ofsted":null,"distance":"On site","url":"https://brockwood.org.uk/"},{"name":"Perins School, Alresford","phase":"Secondary","type":"State","ofsted":null,"distance":"~8-12 miles","url":"https://www.perins.net/"}],"transport":{"commutes":[{"to":"Winchester","mode":"Drive","typical":"~30-40 min","notes":"Via A31 from Alresford side"},{"to":"Petersfield","mode":"Drive","typical":"~20-30 min","notes":"Via rural cross-country routes"}]},"prices":{"summary":"SO24 values in estate-adjacent rural pockets are highly property-specific and typically reflect scarcity, land and setting quality.","asOf":"2026-05","sourceUrl":"https://www.rightmove.co.uk/house-prices/SO24.html"},"thingsToDo":["Walk and cycle surrounding downland and woodland routes","Visit Alresford, Petersfield and South Downs attractions"],"placesToEat":["Country pubs in Cheriton/Alresford/Petersfield belt"],"pros":["Distinctive rural setting with low-density character","Good access to South Downs recreation"],"cons":["Very limited immediate services","Transport and amenities generally require driving"],"whoItSuits":"Suitable for buyers prioritising privacy and countryside context over walkable facilities, especially those comfortable with car-based living.","broadbandMedianMbps":null,"nearestStation":null,"primarySupermarket":null,"images":[],"sources":[{"label":"Brockwood Park School","url":"https://brockwood.org.uk/"},{"label":"Rightmove House Prices SO24","url":"https://www.rightmove.co.uk/house-prices/SO24.html"},{"label":"Winchester City Council","url":"https://www.winchester.gov.uk/"},{"label":"OpenStreetMap SO24 area","url":"https://www.openstreetmap.org/"}]}]'::jsonb) AS value
